def visitor_streak(spec: dict) -> int:
    """Longest run of consecutive days with at least min_count signatures."""
    best = 0
    cur = 0
    for day in spec["days"]:
        if len(day["visitors"]) >= spec["min_count"]:
            cur += 1
            if cur > best:
                best = cur
        else:
            cur = 0
    return best

