def repeat_visitors(spec: dict) -> list:
    """Names that signed on more than one distinct day, sorted."""
    days_by = {}
    for day in spec["days"]:
        for name in day["visitors"]:
            days_by.setdefault(name, set()).add(day["date"])
    return sorted(n for n in days_by if len(days_by[n]) > 1)

