def first_return_day(spec: dict) -> str:
    """Date of the first day when a past signer signs again ('' if none)."""
    seen = set()
    for day in spec["days"]:
        todays = set(day["visitors"])
        if todays & seen:
            return day["date"]
        seen |= todays
    return ""

