def peak_hour(spec: dict) -> str:
    """Busiest event hour as 'hour:count' (ties -> earliest hour)."""
    tally = {}
    for e in spec["events"]:
        tally[e["hour"]] = tally.get(e["hour"], 0) + 1
    if not tally:
        return "none"
    best_h = -1
    best_n = -1
    for h in sorted(tally):
        if tally[h] > best_n:
            best_h = h
            best_n = tally[h]
    return str(best_h) + ":" + str(best_n)

